import * as http from "http";
import { logger } from "../logger"; // adjust import path as needed
import type { TaskStore } from "../task-store"; // adjust import path as needed

const DEFAULT_SSE_PORT = parseInt(process.env["SSE_PORT"] ?? "3001", 10);
const DEFAULT_SSE_HOST = process.env["SSE_HOST"] ?? "127.0.0.1";

export interface SseServerOptions {
  /** Defaults to $SSE_PORT env var, then 3001. Pass 0 to get an OS-assigned port. */
  port?: number;
  host?: string;
}

/**
 * Attempts to start the SSE HTTP server.
 *
 * Returns the `http.Server` instance on success, or `null` if the port is
 * unavailable (or any other bind error). In the null case the stdio MCP
 * server continues unaffected.
 */
export function startSseServer(
  taskStore: TaskStore,
  options: SseServerOptions = {}
): Promise<http.Server | null> {
  const port = options.port ?? DEFAULT_SSE_PORT;
  const host = options.host ?? DEFAULT_SSE_HOST;

  return new Promise<http.Server | null>((resolve) => {
    const server = http.createServer((req, res) => {
      /* ...SSE routing — unchanged... */
      void taskStore; // suppress unused-var until routing is wired
      res.end();
    });

    // Must be attached BEFORE listen() to intercept the error event that
    // fires asynchronously when the OS rejects the bind.
    server.once("error", (err: NodeJS.ErrnoException) => {
      if (err.code === "EADDRINUSE") {
        logger.warn(
          { host, port },
          "SSE port already in use — SSE server unavailable; stdio MCP server continues"
        );
      } else {
        logger.error(
          { host, port, err },
          "SSE server failed to bind — SSE unavailable; stdio MCP server continues"
        );
      }
      // Do NOT call server.close() here: the server never successfully opened.
      resolve(null);
    });

    server.listen(port, host, () => {
      const addr = server.address();
      const bound =
        addr && typeof addr === "object"
          ? { host: addr.address, port: addr.port }
          : { host, port };
      logger.info(bound, "SSE server listening");
      resolve(server);
    });
  });
}
